VALUES
  ('social-worker-moex-06740', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列關於成人晚期（60歲到死亡）的敘述，何者錯誤？', '["神經傳導物改變、血流量減少", "流動智力隨著年齡增加而增長", "肌肉收縮速度和力道減弱、肌肉力量和耐力衰退", "八十歲甚至更老的男性都還可以有性生活"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06741', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列關於阿茲海默型失智症的敘述，何者錯誤？', '["是不可逆轉的腦部異常", "因為失去記憶而發生意外事故，是這個疾病的主要死因", "有基因異常者約30、40歲就發病", "會漸漸引起記憶、知覺、智力、身體控制能力的退化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06742', 'social-worker', 'social-worker-moex-102-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於他人的思想、感受及意圖能夠察覺的程度，稱為：', '["人際覺知", "自我覺知", "社會認知", "社會參考"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "d2ee28ed3e24", "answer_pdf_sha1": "beeb8e1e0c62", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06743', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列文句的成語使用，何者正確？', '["這問題一開始沒解決，如今越來越麻煩，想解決已是「如湯沃雪」，難上加難", "經濟持續不景氣，許多家庭面臨收入頓減的「采薪之憂」，只好盡量撙節開支", "士兵們操演結束都餓極了，坐上餐桌便「嘗鼎一臠」，沒多久就把整鍋飯清空", "他憑著信念與鬥志，成為首屈一指的富豪，在企業界享有「列鼎而食」的尊榮"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06744', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「余聞法人好勝，何以自繪敗狀，令人喪氣若此？譯者曰：『所以昭炯戒、激眾憤、 圖報復也。』則其意深長矣。」下列選項，何者最接近本文意旨？', '["知恥近乎勇", "時窮節乃見", "就有道而正", "莫徒務近功"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06745', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「如今社會上對任何稍有表現的女子都稱之為『女強人』，出於男性之口，似乎並 不完全是讚美的意思。在所有成熟的文化中，『強』字是個令人不安的形容詞。」 下列選項不是上文所呈現的概念的是：', '["看似正面的稱許或許隱藏了負面的評價", "性別有時仍是衡量個體成就的指標之一", "現代女性追求卓越已擺脫來自性別的偏見", "現代成功女性往往會有面對傳統價值的焦慮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06746', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「寫詩，是艾莉絲‧華克劫後餘生的紀念，是她愛自己的方法。至於我，我不寫詩， 不會寫，屬於艾莉絲‧華克那樣的詩感覺與私感覺也未必有，但是，我把每一個日 子當成一首『絕句』來經營。絕句之絕，文學史如何詮釋定義我不管。在我的字典 裡，它是絕無僅有、獨一無二的意思。因此，今天，永遠是時光激流中的孤島！妳 要把它布置成一座花園呢？還是囚牢？還是歲月追殺的戰場？遂也永遠是最現實 的自我倫理課題。」下列敘述最接近上文意旨的選項是：', '["走出戶外，迎向自然", "面對現實，堅守崗位", "境隨心轉，把握當下", "吟詩作對，歌詠人生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06747', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「王維，繪畫上的革命者，他領悟到自己視覺的限制，領悟到「江流天地外」，那 存在於視覺之外的浩大與無限，他放棄了西方繪畫裡透視法（Perspective）的堅持， 知道透視中堅持的景深焦點，其實是人的自大，他開始為視覺極限之外留下了空白。 王維之後，東方繪畫裡的「留白」變成極重要的部分，「留白」正是「江流天地外」 的領悟，不是在繪畫裡表現視覺的自大，相反的，是在領悟自己視覺極限之後才可 能出現的謙虛與寬容。」下列關於「留白」的敘述，何者與上文的內容不相符？', '["留白讓視覺空間有無限擴展的可能", "留白是對透視法的延伸變化與運用", "留白是畫家對自己視線限制的自覺", "留白是東方繪畫中一種自謙的表現"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06748', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「在我們心目中，麻雀是一種最不帶神秘色彩的鳥兒，任何時候，只要我們一打開 窗，便可見到它小巧的身影、聽到它平凡的吱喳聲；它俯仰自如地生活在天地間， 我們無需擔心它逃走、隱遁，它永遠不會自我們視野中消失，於是，它與人類的接 近，竟反而使它獲得了其他鳥兒所獨缺的免於樊籠的自由。」上文中作者從麻雀身 上領會的生存之道，最接近的是：', '["寵辱若驚，貴大患若身", "寵辱不驚，看庭前花開花落；去留無意，望天上雲卷雲舒", "視人之國若視其國，視人之家若視其家，視人之身若視其身", "積土成山，風雨興焉；積水成淵，蛟龍生焉；積善成德，而神明自得，聖心備焉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06749', 'social-worker', 'social-worker-moex-102-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「小小的五分車上／成綑成綑的甘蔗／堆得高比天／即使舉起全線通行的旗號／ 仍然不時絆倒出遊的雲彩    我童年唯一的零食／坐著五分車到處旅行／糖和油菜 花混合的香味／飄過原野，迷惑了麻雀／緩緩傳進學校的每一扇窗    放學後，我 常到鐵道旁等待／遠方五分車駕著風前來／偷偷抽一根，像拉開貧窮的門閂/苦澀的 皮是父親的汗漬／甜膩的汁是我未長大的夢」關於這首詩的旨趣與情境，下列所述 何者為非？', '["詩人童年時唯一的零食是放學後五分車上的甘蔗", "「糖和油菜花混合的香味」，迷惑了麻雀，也迷惑了作者幼稚的心靈", "「小小的五分車」與「堆得高比天的甘蔗」，這種具反差效果的對比手法形成了 文字凸出的視覺形象", "「苦澀的皮是父親的汗漬／甜膩的汁是我未長大的夢」意謂：甘蔗的滋味既是詩 人對親情真切的感受，也是對未來美好的憧憬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "3c05827aeb81", "answer_pdf_sha1": "0c900c3373d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
